import React, { useRef, useEffect, useState } from "react";

function VideoFeed() {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const [detections, setDetections] = useState([]);

  // Start webcam
  useEffect(() => {
    navigator.mediaDevices.getUserMedia({ video: true })
      .then(stream => {
        videoRef.current.srcObject = stream;
      });
  }, []);

  // Capture frame & send to backend
  const detectFrame = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    ctx.drawImage(video, 0, 0);

    const imageData = canvas.toDataURL("image/jpeg");

    try {
      const response = await fetch("http://127.0.0.1:5000/detect", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ image: imageData })
      });

      const data = await response.json();
      setDetections(data);

      drawBoxes(data);
    } catch (err) {
      console.error(err);
    }
  };

  // Draw bounding boxes
  const drawBoxes = (detections) => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    ctx.lineWidth = 2;
    ctx.font = "16px Arial";
    ctx.strokeStyle = "red";
    ctx.fillStyle = "red";

    detections.forEach(det => {
      ctx.strokeRect(det.x1, det.y1, det.x2 - det.x1, det.y2 - det.y1);
      ctx.fillText(det.label, det.x1, det.y1 - 5);
    });
  };

  // Run detection every 1 second
  useEffect(() => {
    const interval = setInterval(() => {
      detectFrame();
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="video-section">
      <div className="camera-feed">
        <div className="camera-header">
          <span className="camera-title">Camera 01 - Entrance</span>
          <div className="live-badge">
            <div className="live-dot"></div>
            LIVE
          </div>
        </div>

        <div style={{ position: "relative" }}>
          <video
            ref={videoRef}
            autoPlay
            muted
            style={{ width: "100%" }}
          />

          {/* Overlay Canvas */}
          <canvas
            ref={canvasRef}
            style={{
              position: "absolute",
              top: 0,
              left: 0,
              width: "100%",
            }}
          />
        </div>

        {/* Alert */}
        {detections.length > 0 && (
          <div className="alert-overlay">
            <div className="alert-text">⚠ INTRUSION DETECTED!</div>
          </div>
        )}
      </div>
    </div>
  );
}

export default VideoFeed;
